export async function resolveContextFromAuthHeader(header) {
  if (!header || typeof header !== "string" || !header.startsWith("Bearer ")) {
    return { user: null, restaurant: null, owner: null, rider: null };
  }
  const token = header.slice(7);
  try {
    const payload = jwt.verify(token, SECRET);
    if (payload.kind === "restaurant") {
      const r = await Restaurant.findById(payload.sub);
      return { user: null, restaurant: r, owner: null, rider: null };
    }
    if (payload.kind === "owner") {
      const o = await Owner.findById(payload.sub);
      return { user: null, restaurant: null, owner: o, rider: null };
    }
    if (payload.kind === "rider") {
      const r = await Rider.findById(payload.sub);
      return { user: null, restaurant: null, owner: null, rider: r };
    }
    const u = await User.findById(payload.sub);
    return { user: u, restaurant: null, owner: null, rider: null };
  } catch {
    return { user: null, restaurant: null, owner: null, rider: null };
  }
}

function cleanupRegistry({ name, map, ttlMs, maxSize }) {
  if (!map || map.size === 0) return 0;
  const now = Date.now();
  let removed = 0;

  // 1) По TTL
  for (const [key, value] of map.entries()) {
    if (value && value.at && now - value.at > ttlMs) {
      map.delete(key);
      removed++;
    }
  }

  // 2) По размеру (если задан)
  if (maxSize && map.size > maxSize) {
    // Удаляем самые старые (в порядке вставки Map сохраняет insertion order)
    const excess = map.size - maxSize;
    let i = 0;
    for (const key of map.keys()) {
      if (i >= excess) break;
      map.delete(key);
      removed++;
      i++;
    }
  }

export function registerRegistry(name, map, ttlMs, maxSize) {
  registries.push({ name, map, ttlMs, maxSize });
  debugLog(JOB_NAME, `registered ${name}`, { ttlMs, maxSize });
}

export function startMemoryCleanupJob() {
  if (task) {
    debugWarn(JOB_NAME, "already started");
    return;
  }
  if (process.env.DISABLE_CRON === "1") {
    debugLog(JOB_NAME, "disabled via env");
    return;
  }

  task = cron.schedule(
    CRON_EXPR,
    () => {
      for (const reg of registries) {
        try {
          cleanupRegistry(reg);
        } catch (e) {
          debugWarn(JOB_NAME, `cleanup ${reg.name} failed`, e?.message);
        }
      }
    },
    { scheduled: true, timezone: "Asia/Dushanbe" },
  );

  debugLog(JOB_NAME, "started", { expr: CRON_EXPR, count: registries.length });

export function stopMemoryCleanupJob() {
  if (task) {
    task.stop();
    task = null;
    debugLog(JOB_NAME, "stopped");
  }
}

export function debugLog(scope, message, data) {
  if (data !== undefined) {
    console.log(`[${scope}] ${message}`, data);
  } else {
    console.log(`[${scope}] ${message}`);
  }
}

export function debugWarn(scope, message, data) {
  if (data !== undefined) {
    console.warn(`[${scope}] ${message}`, data);
  } else {
    console.warn(`[${scope}] ${message}`);
  }
}

export function debugError(scope, message, data) {
  if (data !== undefined) {
    console.error(`[${scope}] ${message}`, data);
  } else {
    console.error(`[${scope}] ${message}`);
  }
}

