function slugify(name) {
  return (
    name
      .toLowerCase()
      .replace(/[^a-z0-9\u0400-\u04FF]+/gi, "-")
      .replace(/^-|-$/g, "")
      .slice(0, 48) || `restaurant-${Date.now()}`
  );
}

