sendChatMessage = async (_p, { orderId, text }, ctx) => {
  const trimmed = (text || "").trim();
  if (!trimmed) {
    throw new GraphQLError("Пустое сообщение", {
      extensions: { code: "BAD_USER_INPUT" },
    });
  }
  const { order, senderType, senderId } = await canAccessOrder(ctx, orderId);

  if (!ALLOWED_STATUSES.includes(order.orderStatus)) {
    throw new GraphQLError("Чат доступен только после назначения курьера", {
      extensions: { code: "BAD_STATE" },
    });
  }

  const msg = await ChatMessage.create({
    orderId,
    senderType,
    senderId,
    text: trimmed,
  });
  const payload = { newChatMessage: msg };
  pubsub.publish(TOPICS.CHAT(orderId.toString()), payload);
  return msg;
}

async function getOrCreateSingleton() {
  try {
    const cfg = await Configuration.findByIdAndUpdate(
      "singleton",
      {
        // ⭐ ШАГ 4: при первом создании singleton заполняем дефолтными значениями ставок
        $setOnInsert: {
          _id: "singleton",
          deliveryBaseKm: DELIVERY_PRICING.baseKm,
          deliveryBasePrice: DELIVERY_PRICING.basePrice,
          deliveryPerKmPrice: DELIVERY_PRICING.perKmPrice,
          deliveryRate: DELIVERY_PRICING.basePrice, // legacy поле = базовая ставка
          taxPercent: 10,
        },
      },
      { new: true, upsert: true, setDefaultsOnInsert: true },
    );
    return cfg;
  } catch (e) {
    if (e.code === 11000) {
      return Configuration.findById("singleton");
    }
    throw e;
  }
}

