  if (lat1 == null || lng1 == null || lat2 == null || lng2 == null) {
    return null;
  }

  const { avgSpeedKmh = 25, bufferSec = 180 } = options;
  const km = haversineKm(lat1, lng1, lat2, lng2);
  const travelSec = (km / avgSpeedKmh) * 3600;
  return Math.round(travelSec + bufferSec);
}

export function haversineKm(lat1, lng1, lat2, lng2) {
  const R = 6371;
  const dLat = ((lat2 - lat1) * Math.PI) / 180;
  const dLng = ((lng2 - lng1) * Math.PI) / 180;
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos((lat1 * Math.PI) / 180) *
      Math.cos((lat2 * Math.PI) / 180) *
      Math.sin(dLng / 2) ** 2;
  return 2 * R * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

export function bearingDeg(lat1, lng1, lat2, lng2) {
  const toRad = (d) => (d * Math.PI) / 180;
  const dLng = toRad(lng2 - lng1);
  const lat1r = toRad(lat1);
  const lat2r = toRad(lat2);
  const y = Math.sin(dLng) * Math.cos(lat2r);
  const x =
    Math.cos(lat1r) * Math.sin(lat2r) -
    Math.sin(lat1r) * Math.cos(lat2r) * Math.cos(dLng);
  const brng = (Math.atan2(y, x) * 180) / Math.PI;
  return (brng + 360) % 360;
}

export function pointInCircle(
  pointLat,
  pointLng,
  centerLat,
  centerLng,
  radiusM,
) {
  const distanceM =
    haversineKm(pointLat, pointLng, centerLat, centerLng) * 1000;
  return distanceM <= radiusM;
}

export function etaSeconds(distanceKm, avgSpeedKmh = 25, bufferSec = 180) {
  const travelSec = (distanceKm / avgSpeedKmh) * 3600;
  return Math.round(travelSec + bufferSec);
}

export function sortByDistance(riderCoords, targetLat, targetLng) {
  return riderCoords
    .map((r) => {
      const coords = r.location?.coordinates || [null, null];
      const [lng, lat] = coords;
      const distance =
        lat != null && lng != null
          ? haversineKm(lat, lng, targetLat, targetLng)
          : Infinity;
      return { ...r, distance };
    })
    .sort((a, b) => {
      if (a.distance === Infinity && b.distance === Infinity) return 0;
      if (a.distance === Infinity) return 1;
      if (b.distance === Infinity) return -1;
      return a.distance - b.distance;
    });
}

function makeKey(from, to) {
  const round = (n) => Math.round(n * 1e5) / 1e5;
  const a = `${round(from[1])},${round(from[0])}`;
  const b = `${round(to[1])},${round(to[0])}`;
  // Всегда сортируем, чтобы A→B == B→A
  return a < b ? `${a}__${b}` : `${b}__${a}`;
}

function getCached(key) {
  const entry = ROUTE_CACHE.get(key);
  if (!entry) return null;
  if (Date.now() - entry.at > CACHE_TTL_MS) {
    ROUTE_CACHE.delete(key);
    return null;
  }
  return entry;
}

function setCached(key, distanceM) {
  // ⭐ LRU eviction: если кеш переполнен — удаляем самые старые записи
  if (ROUTE_CACHE.size >= CACHE_MAX_SIZE) {
    // Удаляем 10% самых старых (в порядке Map insertion order)
    const toDelete = Math.floor(CACHE_MAX_SIZE * 0.1);
    const iter = ROUTE_CACHE.keys();
    for (let i = 0; i < toDelete; i++) {
      const k = iter.next().value;
      if (k) ROUTE_CACHE.delete(k);
    }
  }
  ROUTE_CACHE.set(key, { distanceM, at: Date.now() });
}

