function isValidEmail(s: string) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(s.trim());
}

function isValidPhone(s: string) {
  const clean = s.replace(/[\s\-()]/g, "");
  return /^\+?\d{9,15}$/.test(clean);
}

function isValidPassword(s: string) {
  return typeof s === "string" && s.length >= 6;
}

